#include <chrono>
#include <cmath>
#include <cstdio>
#include <iostream>
#include <iomanip>
#include <limits>
#include <utility>
#include <omp.h>

#define N 2048

#define IDX(i, j) ((i) + (j) * N)

void initialize_data(float* f) {
  for (int j = 0; j < N; ++j) {
    for (int i = 0; i < N; ++i) {
      if (i == 0 || i == N-1) {
        f[IDX(i,j)] = sinf(j * 2 * M_PI / (N - 1));
      }
      else if (j == 0 || j == N-1) {
        f[IDX(i,j)] = sinf(i * 2 * M_PI / (N - 1));
      }
      else {
        f[IDX(i,j)] = 0.0f;
      }
    }
  }
}

void jacobi_step(float* f, const float* f_old, float* error) {
  int block_size = 16;

  #pragma omp parallel for collapse(2) schedule(static)
  for (int block_j = 0; block_j < N/block_size; ++block_j) {
    for (int block_i = 0; block_i < N/block_size; ++block_i) {
      int i_start = block_i * block_size;
      int j_start = block_j * block_size;

      float local_err = 0.0f;

      float f_old_tile[18][18];

      for (int tj = 0; tj < block_size; ++tj) {
        for (int ti = 0; ti < block_size; ++ti) {
          int i = i_start + ti;
          int j = j_start + tj;
          f_old_tile[tj+1][ti+1] = f_old[IDX(i,j)];

          if (ti == 0 && i >= 1) {
            f_old_tile[tj+1][ti] = f_old[IDX(i-1,j)];
          }
          if (ti == block_size-1 && i <= N-2) {
            f_old_tile[tj+1][ti+2] = f_old[IDX(i+1,j)];
          }
          if (tj == 0 && j >= 1) {
            f_old_tile[tj][ti+1] = f_old[IDX(i,j-1)];
          }
          if (tj == block_size-1 && j <= N-2) {
            f_old_tile[tj+2][ti+1] = f_old[IDX(i,j+1)];
          }
        }
      }

      for (int tj = 0; tj < block_size; ++tj) {
        for (int ti = 0; ti < block_size; ++ti) {
          int i = i_start + ti;
          int j = j_start + tj;

          if (j >= 1 && j <= N-2 && i >= 1 && i <= N-2) {
            f[IDX(i,j)] = 0.25f * (f_old_tile[tj+1][ti+2] + 
                                   f_old_tile[tj+1][ti] + 
                                   f_old_tile[tj+2][ti+1] + 
                                   f_old_tile[tj][ti+1]);
            float df = f[IDX(i,j)] - f_old_tile[tj+1][ti+1];
            local_err += df * df;
          }
        }
      }

      #pragma omp atomic
      *error += local_err;
    }
  }
}

int main() {
  auto start_time = std::chrono::steady_clock::now();

  float* f = (float*) aligned_alloc(64, N * N * sizeof(float));
  float* f_old = (float*) aligned_alloc(64, N * N * sizeof(float));
  float* d_f = (float*) aligned_alloc(64, N * N * sizeof(float));
  float* d_f_old = (float*) aligned_alloc(64, N * N * sizeof(float));
  float d_error = 0.0f;

  initialize_data(f);
  initialize_data(f_old);

  for (int i = 0; i < N * N; ++i) {
    d_f[i] = f[i];
    d_f_old[i] = f_old[i];
  }

  float error = std::numeric_limits<float>::max();
  const float tolerance = 1.e-5f;

  const int max_iters = 10000;
  int num_iters = 0;

  auto start = std::chrono::steady_clock::now();

  while (error > tolerance && num_iters < max_iters) {
    d_error = 0.0f;

    jacobi_step(d_f, d_f_old, &d_error);

    std::swap(d_f, d_f_old);

    error = sqrtf(d_error / (N * N));

    if (num_iters % 1000 == 0) {
      std::cout << "Error after iteration " << num_iters << " = " << error << std::endl;
    }

    ++num_iters;
  }

  auto end = std::chrono::steady_clock::now();
  auto time = std::chrono::duration_cast<std::chrono::nanoseconds>(end - start).count();
  std::cout << "Average execution time per iteration: " << (time * 1e-9f) / num_iters << " (s)\n";

  if (error <= tolerance && num_iters < max_iters) {
    std::cout << "PASS" << std::endl;
  }
  else {
    std::cout << "FAIL" << std::endl;
    free(d_f);
    free(d_f_old);
    free(f);
    free(f_old);
    return -1;
  }

  free(d_f);
  free(d_f_old);
  free(f);
  free(f_old);

  auto end_time = std::chrono::steady_clock::now();
  auto total_time = std::chrono::duration_cast<std::chrono::nanoseconds>(end_time - start_time).count();
  double duration = total_time * 1e-9;
  std::cout << "Total elapsed time: " << std::setprecision(4) << duration << " seconds" << std::endl;

  return 0;
}
